INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6e2f88c7-moex-00184', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '甲所有的部分土地長期供公眾通行使用，鄉公所並鋪設柏油道路，設置路燈及負責道路修繕。經 過數十年鄰地的聯外道路系統已相當發達，已少有公眾使用該既成道路。甲希望能使用供公眾使 用既成道路的土地，擬向行政法院提起訴訟恢復既成道路上土地得自由使用收益狀態。甲應提起 下列何種行政訴訟？', '["撤銷之訴", "一般給付之訴", "所有權返還之訴", "確認公法法律關係存否之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00185', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '甲市政府基於成本考量將該市所興建所有的焚化爐，委託乙公司運作經營。由於乙公司人員操作 焚化爐不當，釋放大量戴奧辛等有毒氣體致周邊居民吸入後產生健康的危害。請問受害居民應如 何求償，以下敘述何者正確？', '["甲市政府既已將焚化爐委託乙公司經營管理，受害居民僅能向乙公司行使民事侵權行為之損害 賠償，國家並無責任", "受害人民仍得以甲市政府為賠償義務機關提起國家賠償之訴，不論該焚化爐是否已經委託乙公 司經營管理", "受害人民對於其身體健康的損害，必須證明乙公司人員操作焚化爐有過失，始能請求國家賠償", "受害人民對於身體健康之損害，僅能擇一向乙公司提起民事損害賠償之訴，或以甲市政府為賠 償義務機關提起國家賠償之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00186', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '駕駛人於路邊停車格內停車，主管機關因該處地層下陷，緊急遂請拖吊業者將其車移至適當地點。 駕駛人事後發覺車輛因移置而受有損害。其可提出何種救濟？', '["向法院提起國家賠償", "向主管機關提起民事損害賠償", "向拖吊業者提起民事損害賠償", "向主管機關請求損失補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00001', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-d8653eb5', 'sub-promotion-6ec17a12-01', NULL, 'essay', '我國漁船在海上作業時，由於船員間之衝突，易造成海上喋血傷亡事件，
試述我國遠洋漁船在公海發生海上喋血時，海巡機關應如何應處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "603abf6c33e8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "2712", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "海巡勤務", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00002', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-d8653eb5', 'sub-promotion-6ec17a12-01', NULL, 'essay', '某溪流由山區流經某鄉鎮，再綿延數浬後進入海洋，由於數月前地震造
成山崩後形成堰塞湖，某日堰塞湖溢流及崩塌，大規模土石流及泥水衝
向該鄉鎮並流往海洋，造成 10餘人死亡，尚有 20餘人失聯中，而且道
路及民宅深陷泥淖，又缺乏民生物資，由於災情嚴重，政府立即成立災
害應變中心，整合各項資源執行救災，此時，海巡機關獲命立即前往災
區支援，試問海巡人員可執行那些工作暨其法令依據為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "603abf6c33e8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "2712", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "海巡勤務", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00003', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-d8653eb5', 'sub-promotion-6ec17a12-01', NULL, 'essay', '海巡單位針對轄區船舶及各類運輸工具，實施評鑑分類，以提高船舶進出
